body:
```mlir
module attributes {circt.loweringOptions = "disallowLocalVariables,verifLabels,emittedLineLength=240"}  {
hw.module @Foo(%clock: i1,  %a: i1, %b: i1, %d:i1) -> (res: i1) {
  %reg = sv.reg sym @bar  : !hw.inout<i1>
  %0 = sv.read_inout %reg : !hw.inout<i1>
  %13 = comb.and %a, %b : i1
  sv.always posedge %clock  {
    sv.if %13  {
      sv.passign %reg, %d : i1
    }
  }
  hw.output %0 : i1
}
}
```
emits
```sv
module Foo(     // foo.mlir:2:1
  input  clock, a, b, d,
  output res);

  reg reg_0;    // foo.mlir:3:10

  wire _T = a & b;      // foo.mlir:5:9
  always @(posedge clock) begin // foo.mlir:6:3
    if (_T)     // foo.mlir:7:5
      reg_0 <= d;       // foo.mlir:8:7
  end // always @(posedge)
  assign res = reg_0;   // foo.mlir:4:8, :11:3
endmodule
```
`_T` should not be spilled.  This `_T` is spilled because while the emission of `%13`, `%13` is not defined in the block of AlwayOp. 
```mlir
===== After Prettify Verilog ======
sv.always .. {
  %1 = comb.and %a, %b : i1
  sv.if %1  {
    ....
  }
}

=====After prepareForEmission ====
%1 = comb.and
sv.always .. {
   sv.if %1 { // %1 is not defined in the same block --> spill!
     ... 
   }
}
```
Actually PrettifyVerilog sinks `%1` in the block of always op but PrepareForEmission hoists `%1` again to prohibit temporary in the procedural region.
